    "Jo\u0161 samo jedno \ud83d\udc9b":{en:"Just one more thing \ud83d\udc9b",de:"Nur noch eins \ud83d\udc9b",fr:"Encore une chose \ud83d\udc9b",es:"Solo una cosa m\u00e1s \ud83d\udc9b",it:"Ancora una cosa \ud83d\udc9b",ru:"\u0415\u0449\u0451 \u043a\u043e\u0435-\u0447\u0442\u043e \ud83d\udc9b",pt:"S\u00f3 mais uma coisa \ud83d\udc9b"},
